            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Whether the prompt frames the work as ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "/goal",
                "type": "text"
              },
              {
                "text": " or ",
                "type": "text"
              },
              {
