                  {
                    "type": "code"
                  }
                ],
                "text": "/ralph-loop",
                "type": "text"
              },
              {
                "text": " (both named in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": "). Pick one and document why in the README.",
                "type": "text"
              }
            ],
            "type": "paragraph"
